command:
mkdir -p space && printf 'metrics:
  - {id: m1, dimension: satisfaction}
  - {id: m2, dimension: performance}
' > space/metrics.yaml && printf 'dimensions:
  satisfaction: {opt_in: true, enabled: false}
  performance: {enabled: true}
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-report.sh" --metrics space/metrics.yaml --config space/config.yaml 2>out.txt && ! grep -q '## Satisfaction' out.txt && grep -q '## Performance' out.txt && echo ok 1>&2
